const src = $input.first().json;
const body = src.body || src;
let raw = String(body.url || body.website || '').trim();
if (!raw) { throw new Error('No url provided in request body'); }
if (!/^https?:\/\//i.test(raw)) raw = 'https://' + raw;
const m = raw.match(/^(https?):\/\/([^\/?#]+)([^?#]*)/i);
if (!m) { throw new Error('Invalid url: ' + raw); }
const protocol = m[1].toLowerCase();
const hostname = m[2].toLowerCase();
const pathname = m[3] || '';
const norm = (protocol + '://' + hostname + pathname).replace(/\/$/, '');
let h = 5381;
for (let i = 0; i < norm.length; i++) { h = ((h << 5) + h + norm.charCodeAt(i)) >>> 0; }
return [{ json: { url: norm, url_hash: h.toString(16), host: hostname, email: body.email || null, name: body.name || null, phone: body.phone || null } }];

const rows = $input.all().map(i => i.json).filter(r => r && r.created_at);
const now = Date.now();
const FRESH = 14 * 24 * 3600 * 1000;
const recent = rows.find(r => (now - new Date(r.created_at).getTime()) < FRESH) || null;
const base = $('Normalize + Hash URL').first().json;
return [{ json: { ...base, recent_audit: !!recent, cached: recent } }];

const j = $input.first().json;
const html = String(j.data ?? j.body ?? (typeof j === 'string' ? j : '') ?? '');
const lc = html.toLowerCase();
const pick = (re) => { const m = html.match(re); return m ? m[1].trim() : ''; };
const title = pick(/<title[^>]*>([\s\S]*?)<\/title>/i);
const metaDesc = pick(/<meta[^>]+name=["']description["'][^>]+content=["']([\s\S]*?)["']/i);
const h1count = (html.match(/<h1[\s>]/gi) || []).length;
const canonical = /<link[^>]+rel=["']canonical["']/i.test(html);
const viewport = /<meta[^>]+name=["']viewport["']/i.test(html);
const jsonld = (html.match(/<script[^>]+application\/ld\+json/gi) || []).length;
const hasFaqSchema = /faqpage/i.test(html);
const hasOrgSchema = /["']@type["']\s*:\s*["']organization["']/i.test(lc);
const imgs = (html.match(/<img\b/gi) || []).length;
const imgsAlt = (html.match(/<img\b[^>]*\salt=/gi) || []).length;
const altPct = imgs ? Math.round(100 * imgsAlt / imgs) : 100;
const mailto = /mailto:/i.test(html);
const tel = /tel:/i.test(html);
const ym = html.match(/(?:©|copyright)[^0-9]{0,15}(20\d{2})/i);
const copyrightYear = ym ? ym[1] : '';
const social = {};
['facebook.com','instagram.com','linkedin.com','youtube.com','twitter.com','x.com'].forEach(d => { social[d] = lc.includes(d); });
const text = html.replace(/<script[\s\S]*?<\/script>/gi,' ').replace(/<style[\s\S]*?<\/style>/gi,' ').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim().slice(0, 6000);
return [{ json: { hard: { title, titleLen: title.length, metaDesc, metaLen: metaDesc.length, h1count, canonical, viewport, jsonldBlocks: jsonld, hasFaqSchema, hasOrgSchema, imgCount: imgs, altPct, mailto, tel, copyrightYear, social }, page_text: text, fetched: html.length > 0 } }];

const j = $input.first().json;
const lr = j.lighthouseResult || {};
const cat = lr.categories || {};
const sc = (k) => (cat[k] && typeof cat[k].score === 'number') ? Math.round(cat[k].score * 100) : null;
const audits = lr.audits || {};
const lcp = audits['largest-contentful-paint'] ? audits['largest-contentful-paint'].displayValue : null;
const cls = audits['cumulative-layout-shift'] ? audits['cumulative-layout-shift'].displayValue : null;
const lighthouse = { performance: sc('performance'), accessibility: sc('accessibility'), bestPractices: sc('best-practices'), seo: sc('seo'), lcp, cls, available: Object.keys(cat).length > 0 };
const bundle = { hard: j.hard || {}, lighthouse, fetched: j.fetched !== false };
return [{ json: { url: $('Normalize + Hash URL').first().json.url, audit_id: $('Insert: started').first().json.id, bundle: JSON.stringify(bundle, null, 2), page_text: j.page_text || '' } }];

const j = $input.first().json;
const out = j.output || j;
const points = Array.isArray(out.points) ? out.points : [];
const val = { Pass: 10, Partial: 5, Fail: 0 };
let pass = 0, partial = 0, fail = 0, score = 0;
for (const p of points) { score += (val[p.score]||0); if(p.score==='Pass')pass++; else if(p.score==='Partial')partial++; else fail++; }
const band = score>=90?'Strong site. Minor tune-up opportunities.':score>=70?'Solid foundation with fixable gaps.':score>=50?'Significant issues affecting lead flow and credibility.':'The site is costing the business more than it is earning.';
const base = $('Normalize + Hash URL').first().json;
const url = base.url;
const host = (base.host||'').replace(/^www\./,'');
const preparedFor = (base.name && !/test/i.test(base.name)) ? base.name : (host ? host.charAt(0).toUpperCase()+host.slice(1) : url);
let lh = {};
try { lh = (JSON.parse($('Assemble Signal Bundle').first().json.bundle).lighthouse) || {}; } catch(e) {}
const lhCell = (label, v) => (v===null||v===undefined||v==='') ? '' : '<span class=lhi><b>'+label+'</b> '+v+'</span>';
const lhInner = lh.available ? (lhCell('Performance',lh.performance)+lhCell('Accessibility',lh.accessibility)+lhCell('Best Practices',lh.bestPractices)+lhCell('SEO',lh.seo)+lhCell('LCP',lh.lcp)+lhCell('CLS',lh.cls)) : '<span class=lhi>Data unavailable for this run</span>';
const lhStrip = '<div class=lhwrap><div class=lhlabel>Performance &mdash; Google Lighthouse</div><div class=lh>'+lhInner+'</div></div>';
const cc = [];
if (base.email) cc.push('<b>'+base.email+'</b>');
if (base.phone) cc.push('<b>'+base.phone+'</b>');
const contactLine = cc.length ? '<div class=meta>Contact: '+cc.join(' &nbsp;&middot;&nbsp; ')+'</div>' : '';
const cls = (s)=> s==='Pass'?'pass':(s==='Partial'?'partial':'fail');
const rows = points.map(p=> '<tr><td><span class=pt>'+p.point+'. '+p.name+'</span><br><span class=layer>'+p.layer+'</span></td><td class='+cls(p.score)+'>'+p.score+'</td><td>'+p.evidence+'</td><td>'+p.recommendation+'</td></tr>').join('');
const css = `body{font-family:'Lato',Arial,sans-serif;color:#161616;margin:0;background:#fff;} .band-top{background:#0e0e0e;padding:26px 40px;} .brandmark{font-family:'Playfair Display',serif;font-weight:900;font-size:30px;color:#fff;letter-spacing:.5px;} .brandmark .g{color:#e3c571;} .brandtag{color:#9a9a9a;font-size:11px;letter-spacing:3px;text-transform:uppercase;margin-top:4px;} .wrap{max-width:780px;margin:0 auto;padding:34px 40px 40px;} .kicker{text-transform:uppercase;letter-spacing:3px;font-size:11px;color:#a07f24;font-weight:700;} .h1{font-family:'Playfair Display',serif;font-size:25px;font-weight:700;margin:6px 0 2px;} .meta{color:#555;font-size:13px;margin:6px 0;} .meta b{color:#161616;} .scorewrap{border-left:5px solid #e3c571;padding-left:16px;margin:16px 0 14px;} .score{font-family:'Playfair Display',serif;font-size:48px;font-weight:900;line-height:1;} .score span{font-size:22px;color:#999;} .tally{font-size:14px;font-weight:700;margin-top:6px;} .band{font-style:italic;color:#444;margin-top:4px;} .lhwrap{margin:0 0 22px;} .lhlabel{font-size:10px;letter-spacing:2px;text-transform:uppercase;color:#a07f24;font-weight:700;margin-bottom:7px;} .lh{display:flex;flex-wrap:wrap;gap:8px;} .lhi{background:#f7f4ea;border:1px solid #e6dcc0;border-radius:4px;padding:5px 11px;font-size:12px;color:#555;} .lhi b{color:#161616;} table{border-collapse:collapse;width:100%;font-size:12.5px;} th{background:#0e0e0e;color:#fff;text-align:left;padding:9px;font-weight:700;} td{border:1px solid #e6e6e6;padding:9px;vertical-align:top;} .pt{font-weight:700;} .layer{color:#a07f24;font-size:9.5px;letter-spacing:1.5px;text-transform:uppercase;} .c{text-align:center;} .pass{text-align:center;font-weight:700;color:#1a7f37;} .partial{text-align:center;font-weight:700;color:#a07f24;} .fail{text-align:center;font-weight:700;color:#b3261e;} .foot{margin-top:30px;border-top:3px solid #e3c571;padding-top:16px;font-size:12px;color:#555;line-height:1.6;} .foot .b{font-family:'Playfair Display',serif;font-weight:700;color:#161616;font-size:15px;}`;
const html = `<!DOCTYPE html><html><head><meta charset=utf-8><link href='https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700;900&family=Lato:wght@400;700&display=swap' rel='stylesheet'><style>${css}</style></head><body><div class=band-top><div class=brandmark>Simpl<span class=g>Works</span></div><div class=brandtag>Web Design &amp; AI Automation</div></div><div class=wrap><div class=kicker>10-Point Website Friction Audit</div><div class=h1>Prepared for ${preparedFor}</div><div class=meta>Website audited: <b>${url}</b></div>${contactLine}<div class=scorewrap><div class=score>${score}<span>/100</span></div><div class=tally>${pass} Pass &nbsp;&middot;&nbsp; ${partial} Partial &nbsp;&middot;&nbsp; ${fail} Fail</div><div class=band>${band}</div></div>${lhStrip}<table><tr><th>Point</th><th class=c>Score</th><th>Evidence</th><th>Recommendation</th></tr>${rows}</table><div class=foot><span class=b>SimplWorks</span><br>Knoxville, TN &nbsp;&middot;&nbsp; stephanie@simplworks.ai &nbsp;&middot;&nbsp; 678.617.4598 &nbsp;&middot;&nbsp; simplworks.ai</div></div></body></html>`;
return [{ json: { audit_id: $('Insert: started').first().json.id, url, score, pass, partial, fail, tally: pass+' Pass / '+partial+' Partial / '+fail+' Fail', band, points, report_html: html, email: base.email, phone: base.phone, name: base.name, preparedFor } }];

const e = $input.first().json || {};
const wf = e.workflow ? e.workflow.name : 'Friction Audit Engine';
const exec = e.execution || {};
const node = exec.lastNodeExecuted || 'unknown node';
const msg = (exec.error && exec.error.message) ? exec.error.message : 'unknown error';
const urlInfo = (exec.error && exec.error.node) ? (' [' + exec.error.node.name + ']') : '';
return [{ json: { text: '🚨 ' + wf + ' FAILED at "' + node + '"' + urlInfo + '\n' + msg } }];

const c = $('Compute Score + Tally').first().json;
const out = {
  from: 'SimplWorks <audit@simplworks.ai>',
  to: [ c.email || 'stephanie@simplworks.ai' ],
  subject: 'Your SimplWorks Friction Audit - ' + c.score + '/100',
  html: c.report_html
};
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  if (buf && buf.length) {
    out.attachments = [{ filename: 'SimplWorks-Friction-Audit-' + c.score + '.pdf', content: buf.toString('base64') }];
  }
} catch (e) {}
return [{ json: out }];

